import "timezone"
import "date"

option location = timezone.location(name: "Europe/Rome")

// Usa il time range selezionato in Grafana
// Puoi usare "Last 1 year" oppure selezionare un range custom
startOfPeriod = date.truncate(t: v.timeRangeStart, unit: 1y)
endOfPeriod = date.add(d: 1y, to: startOfPeriod)

from(bucket: "Solaredge")
  |> range(start: startOfPeriod, stop: endOfPeriod)
  |> filter(fn: (r) => r["_measurement"] == "web" and r["_field"] == "Site")
  |> filter(fn: (r) => 
      r["endpoint"] == "PRODUCTION_ENERGY" or 
      r["endpoint"] == "IMPORT_ENERGY" or 
      r["endpoint"] == "EXPORT_ENERGY"
  )
  
  // Aggreghiamo per mese usando il fuso orario configurato
  |> aggregateWindow(
      every: 1mo, 
      fn: sum, 
      createEmpty: true,
      timeSrc: "_start",
      location: location
  )
  
  // Riempiamo eventuali valori mancanti con zero
  |> fill(value: 0.0)
  
  // Trasformiamo da formato lungo a formato largo
  |> pivot(rowKey: ["_time"], columnKey: ["endpoint"], valueColumn: "_value")
  
  // Gestiamo eventuali valori null dopo il pivot
  |> map(fn: (r) => ({ r with 
      prod: if exists r.PRODUCTION_ENERGY then r.PRODUCTION_ENERGY else 0.0,
      imp: if exists r.IMPORT_ENERGY then r.IMPORT_ENERGY else 0.0,
      exp: if exists r.EXPORT_ENERGY then r.EXPORT_ENERGY else 0.0
  }))
  
  // Calcoliamo le metriche derivate
  |> map(fn: (r) => ({ 
      _time: r._time,
      Produzione: r.prod,
      Prelievo: r.imp,
      Immissione: r.exp,
      Consumo: r.prod + r.imp - r.exp,
      Autoconsumo: r.prod - r.exp
  }))
  
  // Filtriamo solo i dati entro il periodo selezionato
  |> filter(fn: (r) => r._time < endOfPeriod)

import "timezone"
import "date"

option location = timezone.location(name: "Europe/Rome")

today_start = date.truncate(t: now(), unit: 1d)

from(bucket: "Solaredge_Realtime")
  |> range(start: today_start)
  |> filter(fn: (r) => r["_measurement"] == "realtime")
  |> filter(fn: (r) => r["_field"] == "Meter")
  |> filter(fn: (r) => r["endpoint"] == "Power")
  // Nessuna aggregazione, dati grezzi
  |> map(fn: (r) => ({
      _time: r._time,
      // Se è negativo (prelievo) mettiamo 0, altrimenti teniamo il valore (immissione)
      "Immissione": if r._value < 0.0 then 0.0 else r._value
    }))
  // Opzionale: filtrare via gli zeri per alleggerire il grafico se vuoi vedere solo quando immetti davvero
  // |> filter(fn: (r) => r.Immissione > 0.0)
  |> yield(name: "immissione_raw")

import "timezone"
import "date"

option location = timezone.location(name: "Europe/Rome")

today_start = date.truncate(t: now(), unit: 1d)

from(bucket: "Solaredge_Realtime")
  |> range(start: today_start)
  |> filter(fn: (r) =>
      r._measurement == "realtime" and
      ((r._field == "Inverter" and r.endpoint == "Power Ac") or
       (r._field == "Meter" and r.endpoint == "Power"))
  )
  // Allineamento temporale (fondamentale per calcoli tra serie diverse)
  |> aggregateWindow(every: 5s, fn: mean, createEmpty: false)
  
  // Pivot invece di Join
  |> keep(columns: ["_time", "_value", "_field"])
  |> pivot(rowKey:["_time"], columnKey: ["_field"], valueColumn: "_value")
  
  // Calcolo Autoconsumo
  |> map(fn: (r) => ({
      _time: r._time,
      _prod: if exists r.Inverter then r.Inverter else 0.0,
      _meter: if exists r.Meter then r.Meter else 0.0
  }))
  |> map(fn: (r) => ({
      _time: r._time,
      Autoconsumo: if r._meter >= 0.0 
                   then r._prod - r._meter  // Se esporto: Prod - Export
                   else r._prod             // Se importo: Tutto quello che produco lo consumo
  }))
  // Filtro valori negativi spuri (non dovrebbe succedere, ma per sicurezza)
  |> filter(fn: (r) => r.Autoconsumo >= 0.0)
  |> yield(name: "autoconsumo_ottimizzato")

import "date"
import "join"
import "timezone"

option location = timezone.location(name: "Europe/Rome")

// ============================================================================
// PARAMETRI CONFIGURABILI - Modifica questi valori in base alla tua situazione
// ============================================================================

// Prezzo Scambio come percentuale del PUN (es. 1.00 = 100% del PUN)
// Valore tipico: 0.95 - 1.05
// Default fittizio: 1.00 (uguale al PUN)
prezzo_scambio_percentuale = 1.00

// Prezzo Eccedenza come percentuale del PUN (es. 0.90 = 90% del PUN)
// Valore tipico: 0.85 - 0.95
// Default fittizio: 0.90 (90% del PUN)
prezzo_eccedenza_percentuale = 0.90

// Tassazione personale sulle eccedenze (es. 0.40 = 40%)
// Valori comuni:
//   0.00 = nessuna tassazione (detrazioni 100%)
//   0.23 = IRPEF 23% (primo scaglione)
//   0.40 = tassazione standard 40%
// Default fittizio: 0.00 (nessuna tassazione)
tassazione_eccedenza = 0.00

// ============================================================================
// FINE PARAMETRI CONFIGURABILI
// ============================================================================

energia = from(bucket: "Solaredge")
  |> range(start: 0)
  |> filter(fn: (r) => 
      r._measurement == "web" and 
      r._field == "Site" and
      (r.endpoint == "EXPORT_ENERGY" or r.endpoint == "IMPORT_ENERGY")
  )
  |> aggregateWindow(every: 1mo, fn: sum, location: location, timeSrc: "_start")
  |> pivot(rowKey: ["_time"], columnKey: ["endpoint"], valueColumn: "_value")
  |> map(fn: (r) => ({
      _time: r._time,
      year: string(v: date.year(t: r._time)),
      month: string(v: date.month(t: r._time)),
      immissione_wh: r.EXPORT_ENERGY,
      prelievo_wh: r.IMPORT_ENERGY
  }))
  |> group()

pun = from(bucket: "GME")
  |> range(start: 0)
  |> filter(fn: (r) => r._measurement == "gme_monthly_avg" and r._field == "pun_kwh_avg")
  |> map(fn: (r) => ({
      _time: r._time,
      year: r.year,
      month: string(v: date.month(t: r._time)),
      pun: r._value
  }))
  |> group()

join.inner(
  left: energia,
  right: pun,
  on: (l, r) => l.year == r.year and l.month == r.month,
  as: (l, r) => {
    immissione_kwh = l.immissione_wh / 1000.0
    prelievo_kwh = l.prelievo_wh / 1000.0
    scambio_kwh = if immissione_kwh < prelievo_kwh then immissione_kwh else prelievo_kwh
    eccedenza_kwh = if immissione_kwh > prelievo_kwh then immissione_kwh - prelievo_kwh else 0.0
    rimborso_scambio = scambio_kwh * r.pun * prezzo_scambio_percentuale
    rimborso_eccedenza_lordo = eccedenza_kwh * r.pun * prezzo_eccedenza_percentuale
    rimborso_eccedenza_netto = rimborso_eccedenza_lordo * (1.0 - tassazione_eccedenza)
    return {_time: l._time, _value: rimborso_scambio + rimborso_eccedenza_netto}
  }
)
  |> sum()
  |> map(fn: (r) => ({"Rimborsi Immissione Netti": r._value}))

import "timezone"
import "date"

option location = timezone.location(name: "Europe/Rome")

// CAMBIA QUI LA METRICA DA CONFRONTARE:
// PRODUCTION_ENERGY, IMPORT_ENERGY, EXPORT_ENERGY, ecc.
target_metric = "PRODUCTION_ENERGY"

from(bucket: "Solaredge")
  // Prendi tutto lo storico
  |> range(start: 0, stop: now())
  |> filter(fn: (r) => r["_measurement"] == "web" and r["_field"] == "Site")
  |> filter(fn: (r) => r["endpoint"] == target_metric)
  
  // Aggregazione mensile con fuso orario corretto
  |> aggregateWindow(
      every: 1mo, 
      fn: sum, 
      createEmpty: false,
      timeSrc: "_start",
      location: location
  )
  
  // Estrai Anno e Mese dal timestamp aggregato
  |> map(fn: (r) => ({ 
      r with 
      year: string(v: date.year(t: r._time)),
      month: date.month(t: r._time)
  }))
  
  // Mappa i nomi dei mesi
  |> map(fn: (r) => ({
      r with
      month_name: if r.month == 1 then "Gennaio"
        else if r.month == 2 then "Febbraio"
        else if r.month == 3 then "Marzo"
        else if r.month == 4 then "Aprile"
        else if r.month == 5 then "Maggio"
        else if r.month == 6 then "Giugno"
        else if r.month == 7 then "Luglio"
        else if r.month == 8 then "Agosto"
        else if r.month == 9 then "Settembre"
        else if r.month == 10 then "Ottobre"
        else if r.month == 11 then "Novembre"
        else "Dicembre"
  }))
  
  // Pivot per avere gli anni come colonne
  |> group()
  |> pivot(rowKey: ["month", "month_name"], columnKey: ["year"], valueColumn: "_value")
  |> sort(columns: ["month"])
  |> drop(columns: ["month"])

